diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..b05603ca5757 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4826,9 +4826,35 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
           return new ICmpInst(I.getSwappedPredicate(), X,
                               ConstantExpr::getNeg(RHSC));
   }
-
   if (Instruction * R = foldICmpXorXX(I, Q, *this))
     return R;
+
+  // Fold (icmp pred (~X ^ Y), ~Z) -> (icmp swap_pred (X ^ Y), Z).
+  // This is valid because ~X = -X-1, so comparing with ~X is like
+  // comparing with X but with the comparison direction flipped.
+  {
+    Value *X, *Y, *Z;
+    if (match(Op0, m_OneUse(m_c_Xor(m_Xor(m_Value(X), m_AllOnes()),
+                                   m_Value(Y)))) &&
+        match(Op1, m_Xor(m_Value(Z), m_AllOnes()))) {
+      Value *NewXor = Builder.CreateXor(X, Y);
+      return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), NewXor, Z);
+    }
+  }
+
+  // Fold (icmp pred (~X ^ Y), ~X) -> (icmp swap_pred (X ^ Y), X).
+  // Special case of the above where Z == X, so Op1 (~X) may have
+  // multiple uses (it's used both in the xor and as the cmp operand).
+  // This is a more specific pattern when Z == X.
+  {
+    Value *X, *Y;
+    if (match(Op0, m_OneUse(m_c_Xor(m_Xor(m_Value(X), m_AllOnes()),
+                                   m_Value(Y)))) &&
+        match(Op1, m_Xor(m_Specific(X), m_AllOnes()))) {
+      Value *NewXor = Builder.CreateXor(X, Y);
+      return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), NewXor, X);
+    }
+  }
   if (Instruction *R = foldICmpOrXX(I, Q, *this))
     return R;

